import os
import sys
from openai import OpenAI

SYSTEM_INSTRUCTIONS = (
    "You are a helpful customer support assistant. "
    "Be concise, polite, and accurate. "
    "If you do not know the answer, ask for clarification or suggest contacting support."
)

def main():
    api_key = os.getenv("OPENAI_API_KEY")
    if not api_key:
        print("Error: OPENAI_API_KEY environment variable is not set.", file=sys.stderr)
        sys.exit(1)

    client = OpenAI(api_key=api_key)

    print("Customer support chatbot started. Type 'exit' to quit.")
    while True:
        try:
            user_input = input("User: ").strip()
        except (EOFError, KeyboardInterrupt):
            print()
            break

        if not user_input:
            continue

        if user_input.lower() in {"exit", "quit"}:
            break

        prompt = f"{SYSTEM_INSTRUCTIONS}\n\nUser: {user_input}"

        try:
            response = client.responses.create(
                model="gpt-4.1-mini",
                input=prompt,
            )
            print("Assistant:", response.output_text)
        except Exception as e:
            print(f"Error: {e}", file=sys.stderr)

if __name__ == "__main__":
    main()